1	export type Cell = [number, number]; // [x, y]
2	
3	type CellKey = string;
4	
5	const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;
6	const fromKey = (key: CellKey): Cell => key.split(",").map(Number) as Cell;
7	
8	const NEIGHBOR_OFFSETS: Cell[] = [
9	  [-1, -1], [0, -1], [1, -1],
10	  [-1, 0], [1, 0],
11	  [-1, 1], [0, 1], [1, 1],
12	];
13	
14	const NEIGHBORS_TO_SURVIVE = 2;
15	const NEIGHBORS_TO_BIRTH = 3;
16	
17	const isAliveNextGeneration = (isAlive: boolean, liveNeighbors: number): boolean =>
18	  liveNeighbors === NEIGHBORS_TO_BIRTH ||
19	  (isAlive && liveNeighbors === NEIGHBORS_TO_SURVIVE);
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const living = new Set(cells.map(toKey));
23	  const neighborCounts = new Map<CellKey, number>();
24	
25	  for (const [x, y] of cells) {
26	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
27	      const key = toKey([x + dx, y + dy]);
28	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
29	    }
30	  }
31	
32	  const next: Cell[] = [];
33	  for (const [key, liveNeighbors] of neighborCounts) {
34	    if (isAliveNextGeneration(living.has(key), liveNeighbors)) {
35	      next.push(fromKey(key));
36	    }
37	  }
38	  return next;
39	}
40

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("an empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 3 overpopulation: center cell with 4 live neighbors dies — ### / .#. / ### → #.# / #.# / #.#", () => {
15	    const gen0: Cell[] = [
16	      [0, 0], [1, 0], [2, 0],
17	      [1, 1],
18	      [0, 2], [1, 2], [2, 2],
19	    ];
20	    const result = nextGeneration(gen0);
21	    const sorted = (cells: Cell[]) =>
22	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
23	    // Center (1,1) has 4 live neighbors → dies (Rule 3).
24	    expect(result).not.toContainEqual([1, 1]);
25	    // Full next generation per the rules (the prompt's 3×3 sketch is
26	    // illustrative only; cells are also born just outside that window).
27	    expect(sorted(result)).toEqual(
28	      sorted([
29	        [0, 0], [2, 0],
30	        [1, -1], [1, 3],
31	        [1, 0], [1, 2],
32	        [0, 2], [2, 2],
33	      ]),
34	    );
35	  });
36	  it("Rule 4 reproduction: a dead cell with exactly 3 live neighbors becomes alive — (1,1) born from [(0,0),(1,0),(0,1)]", () => {
37	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
38	    expect(result).toContainEqual([1, 1]);
39	  });
40	  it("Rule 2 survival: a live cell with 2 live neighbors lives on — (1,0) survives in ### / ... / .#.", () => {
41	    // Gen 0: (1,0) is alive with exactly 2 live neighbors (0,0) and (2,0).
42	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]]);
43	    expect(result).toContainEqual([1, 0]);
44	  });
45	  it("Block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
46	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
47	    const sorted = (cells: Cell[]) =>
48	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
49	    expect(sorted(nextGeneration(block))).toEqual(sorted(block));
50	  });
51	  it.todo("Blinker oscillates — vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]");
52	  it.todo("handles negative coordinates");
53	});
